import { createPortal } from "react-dom";

export default function Header() {
  const headerRoot = document.getElementById("header");

  if (!headerRoot) return null;

  return createPortal(
    <a href="/" className="header-inner">
      <img src="../assets/images/logo.svg" alt="" />
    </a>,
    headerRoot
  );
}
